pub fn get_reachable(&self, symbol: &str, max_depth: usize) -> Result<Vec<ReachablePath>> {
    let mut visited = HashSet::new();
    let mut results = Vec::new();
    let mut queue = VecDeque::new();

    queue.push_back((symbol_id, vec![], 0));

    while let Some((current, path, depth)) = queue.pop_front() {
        if depth > max_depth || visited.contains(&current) {
            continue;
        }
        visited.insert(current);

        // Use existing get_callees() primitive
        for callee in self.symbol_graph.get_callees(current)? {
            let mut new_path = path.clone();
            new_path.push(callee.symbol.clone());
            results.push(ReachablePath { target: callee.symbol, path: new_path.clone(), depth: depth + 1 });
            queue.push_back((callee.symbol.id, new_path, depth + 1));
        }
    }
    Ok(results)
}
